const e=JSON.parse('{"key":"v-3b648b66","path":"/coding/csharp.html","title":"C#","lang":"zh-CN","frontmatter":{"date":"2022-09-29T00:00:00.000Z","icon":"code","category":["编程"],"tag":["编程语言"],"description":"C# 对此语言来说，我还只是个初学者，因此本篇文章目前不会有太多内容。 安装与开发环境配置 C# 的环境配置是我接触过的语言中最简单的之一。（仅 Rust 可与之一战） 进入.NET官网下载 .NET SDK x64 安装包并安装。你可以在 cmd 中运行 dotnet -h 测试环境是否完善。 vscode 中安装 C# 扩展。后续记得看右下角可能出现的提示。 打开你的项目文件夹，终端中输入 dotnet new console 创建项目。 F5 编译运行。","head":[["meta",{"property":"og:url","content":"https://absx.pages.dev/coding/csharp.html"}],["meta",{"property":"og:site_name","content":"绝对值_x的博客"}],["meta",{"property":"og:title","content":"C#"}],["meta",{"property":"og:description","content":"C# 对此语言来说，我还只是个初学者，因此本篇文章目前不会有太多内容。 安装与开发环境配置 C# 的环境配置是我接触过的语言中最简单的之一。（仅 Rust 可与之一战） 进入.NET官网下载 .NET SDK x64 安装包并安装。你可以在 cmd 中运行 dotnet -h 测试环境是否完善。 vscode 中安装 C# 扩展。后续记得看右下角可能出现的提示。 打开你的项目文件夹，终端中输入 dotnet new console 创建项目。 F5 编译运行。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-07-13T07:48:32.000Z"}],["meta",{"property":"article:tag","content":"编程语言"}],["meta",{"property":"article:published_time","content":"2022-09-29T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-07-13T07:48:32.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"C#\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2022-09-29T00:00:00.000Z\\",\\"dateModified\\":\\"2023-07-13T07:48:32.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"安装与开发环境配置","slug":"安装与开发环境配置","link":"#安装与开发环境配置","children":[]}],"git":{"createdTime":1689173144000,"updatedTime":1689234512000,"contributors":[{"name":"lxl66566","email":"18259734087@163.com","commits":2}]},"readingTime":{"minutes":0.57,"words":170},"filePathRelative":"coding/csharp.md","localizedDate":"2022年9月29日","excerpt":"<h1> C#</h1>\\n<p>对此语言来说，我还只是个初学者，因此本篇文章目前不会有太多内容。</p>\\n<h2> 安装与开发环境配置</h2>\\n<p>C# 的环境配置是我接触过的语言中最简单的之一。（仅 Rust 可与之一战）</p>\\n<ol>\\n<li>进入<a href=\\"https://dotnet.microsoft.com/en-us/download\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">.NET官网</a>下载 .NET SDK x64 安装包并安装。你可以在 cmd 中运行 <code>dotnet -h</code> 测试环境是否完善。</li>\\n<li>vscode 中安装 C# 扩展。后续记得看右下角可能出现的提示。</li>\\n<li>打开你的项目文件夹，终端中输入 <code>dotnet new console</code> 创建项目。</li>\\n<li>F5 编译运行。</li>\\n</ol>","autoDesc":true}');export{e as data};
